type WalletProviderEvidenceScenarioOverrides = Partial<Record<WalletProviderQaScenarioId, {
  evidenceStatus?: WalletProviderEvidenceStatus;
  submittedArtifacts?: WalletProviderEvidenceArtifact[];
}>>;

const createWalletProviderEvidenceScenario = (
  scenarioId: WalletProviderQaScenarioId,
  gate: WalletProviderQaReadinessGate,
  overrides: WalletProviderEvidenceScenarioOverrides = {},
): WalletProviderEvidenceScenario => {
  const qaScenario = gate.scenarios.find((scenario) => scenario.id === scenarioId);
  const override = overrides[scenarioId];
  const evidenceStatus = override?.evidenceStatus ?? walletProviderEvidenceStatusFor(scenarioId, Boolean(qaScenario));
  const releaseImpact = walletProviderEvidenceReleaseImpactFor(evidenceStatus);

  return {
    id: scenarioId,
    label: walletProviderEvidenceLabels[scenarioId],
    provider: walletProviderEvidenceProviderLabels[scenarioId],
    expectedArtifacts: expectedWalletProviderArtifacts(scenarioId),
    submittedArtifacts: override?.submittedArtifacts ?? submittedWalletProviderArtifacts(scenarioId),
    evidenceStatus,
    reviewState: walletProviderEvidenceReviewStateFor(evidenceStatus),
    releaseImpact,
    reviewerRole: "internal_operator",
    serviceGate: walletProviderEvidenceServiceGates[scenarioId],
    degradationPath: walletProviderEvidenceDegradationPaths[scenarioId],
    nextAction: walletProviderEvidenceNextActions[scenarioId],
    boundary: walletProviderEvidenceBoundary,
  };
};

const walletProviderEvidenceImpactPriority: Record<WalletProviderEvidenceReleaseImpact, number> = {
  blocked: 0,
  review_required: 1,
  ready: 2,
  not_applicable: 3,
};

const summarizeWalletProviderEvidenceIntake = (
  scenarios: WalletProviderEvidenceScenario[],
): WalletProviderEvidenceIntake["summary"] => {
  const topScenario = [...scenarios].sort((left, right) => {
    const impactDelta = walletProviderEvidenceImpactPriority[left.releaseImpact] -
      walletProviderEvidenceImpactPriority[right.releaseImpact];

    if (impactDelta !== 0) {
      return impactDelta;
    }

    return walletProviderEvidenceScenarioOrder.indexOf(left.id) - walletProviderEvidenceScenarioOrder.indexOf(right.id);
  })[0] ?? scenarios[0];

  return {
    totalScenarios: scenarios.length,
    approvedScenarios: scenarios.filter((scenario) => scenario.evidenceStatus === "approved").length,
    submittedScenarios: scenarios.filter((scenario) => scenario.evidenceStatus === "submitted").length,
    missingScenarios: scenarios.filter((scenario) => scenario.evidenceStatus === "missing").length,
    rejectedScenarios: scenarios.filter((scenario) => scenario.evidenceStatus === "rejected").length,
    expiredScenarios: scenarios.filter((scenario) => scenario.evidenceStatus === "expired").length,
    releaseBlockers: scenarios.filter((scenario) => scenario.releaseImpact === "blocked").length,
    reviewRequiredScenarios: scenarios.filter((scenario) => scenario.releaseImpact === "review_required").length,
    topScenarioId: topScenario.id,
    topNextAction: topScenario.nextAction,
  };
};

export const createWalletProviderEvidenceIntake = (
  gate: WalletProviderQaReadinessGate,
  overrides: WalletProviderEvidenceScenarioOverrides = {},
): WalletProviderEvidenceIntake => {
  const scenarios = walletProviderEvidenceScenarioOrder.map((scenarioId) =>
    createWalletProviderEvidenceScenario(scenarioId, gate, overrides),
  );
  const summary = summarizeWalletProviderEvidenceIntake(scenarios);

  return {
    summary,
    scenarios,
    boundary: walletProviderEvidenceBoundary,
    nextAction: summary.topNextAction,
  };
};

const walletProviderEvidenceApprovalRuleLabels: Record<WalletProviderEvidenceApprovalRuleId, LocalizedText> = {
  "live-evidence-status": localized("Live evidence status", "真实证据状态", "真實證據狀態"),
  "non-live-boundary": localized("Non-live boundary", "非实时边界", "非即時邊界"),
  "required-artifacts": localized("Required artifacts", "必需证据", "必需證據"),
  "reviewer-approval": localized("Reviewer approval", "审核批准", "審核批准"),
  "service-gate": localized("Service gate", "服务门禁", "服務門禁"),
};

const walletProviderEvidenceApprovalStatePriority: Record<WalletProviderEvidenceApprovalScenario["approvalState"], number> = {
  blocked: 0,
  review_required: 1,
  approved: 2,
  not_applicable: 3,
};

const walletProviderEvidenceApprovalRuleStatePriority: Record<WalletProviderEvidenceApprovalRuleState, number> = {
  blocked: 0,
  needs_review: 1,
  passed: 2,
  not_applicable: 3,
};

const walletProviderEvidenceApprovalReleaseImpact: Record<
  WalletProviderEvidenceApprovalScenario["approvalState"],
  WalletProviderEvidenceReleaseImpact
> = {
  approved: "ready",
  blocked: "blocked",
  not_applicable: "not_applicable",
  review_required: "review_required",
};

const walletProviderEvidenceApprovalIds = (ids: string[]) => ids.length > 0 ? ids.join(", ") : "none";

const createWalletProviderArtifactCoverage = (
  scenario: WalletProviderEvidenceScenario,
): WalletProviderArtifactCoverage => {
  const requiredArtifacts = scenario.expectedArtifacts.filter((artifact) => artifact.required);
  const submittedArtifacts = scenario.submittedArtifacts.filter((artifact) => Boolean(artifact.reference));
  const submittedArtifactTypes = new Set(submittedArtifacts.map((artifact) => artifact.artifactType));
  const missingRequiredArtifactIds = requiredArtifacts
    .filter((artifact) => !submittedArtifactTypes.has(artifact.artifactType))
    .map((artifact) => artifact.id);

  return {
    requiredArtifactIds: requiredArtifacts.map((artifact) => artifact.id),
    submittedArtifactIds: submittedArtifacts.map((artifact) => artifact.id),
    submittedArtifactReferences: submittedArtifacts.map((artifact) => artifact.reference ?? artifact.id),
    missingRequiredArtifactIds,
    requiredCount: requiredArtifacts.length,
    submittedRequiredCount: requiredArtifacts.length - missingRequiredArtifactIds.length,
    optionalCount: scenario.expectedArtifacts.filter((artifact) => !artifact.required).length,
    complete: missingRequiredArtifactIds.length === 0,
  };
};

const walletProviderEvidenceApprovalRule = (
  id: WalletProviderEvidenceApprovalRuleId,
  state: WalletProviderEvidenceApprovalRuleState,
  evidence: LocalizedText,
  nextAction: LocalizedText,
): WalletProviderEvidenceApprovalRule => ({
  evidence,
  id,
  label: walletProviderEvidenceApprovalRuleLabels[id],
  nextAction,
  state,
});

const createWalletProviderApprovalRules = (
  scenario: WalletProviderEvidenceScenario,
  qaScenario: WalletProviderQaReadinessGate["scenarios"][number] | undefined,
  artifactCoverage: WalletProviderArtifactCoverage,
): WalletProviderEvidenceApprovalRule[] => {
  const liveEvidenceStatus = qaScenario?.liveEvidenceStatus ?? "missing";
  const missingIds = walletProviderEvidenceApprovalIds(artifactCoverage.missingRequiredArtifactIds);
  const missingArtifactState: WalletProviderEvidenceApprovalRuleState = scenario.evidenceStatus === "not_applicable"
    ? "not_applicable"
    : artifactCoverage.complete
      ? "passed"
      : scenario.evidenceStatus === "submitted"
        ? "needs_review"
        : "blocked";
  const reviewerApprovalState: WalletProviderEvidenceApprovalRuleState = scenario.evidenceStatus === "not_applicable"
    ? "not_applicable"
    : scenario.evidenceStatus === "approved"
      ? "passed"
      : scenario.evidenceStatus === "submitted"
        ? "needs_review"
        : "blocked";
  const liveEvidenceRuleState: WalletProviderEvidenceApprovalRuleState =
    scenario.evidenceStatus === "not_applicable" || liveEvidenceStatus === "not_applicable"
      ? "not_applicable"
      : scenario.evidenceStatus === "approved" && liveEvidenceStatus === "ready"
        ? "passed"
        : scenario.evidenceStatus === "submitted"
          ? "needs_review"
          : "blocked";
  const serviceGateState: WalletProviderEvidenceApprovalRuleState =
    scenario.evidenceStatus === "rejected" ||
    scenario.evidenceStatus === "expired" ||
    liveEvidenceStatus === "blocked"
      ? "blocked"
      : "passed";

  return [
    walletProviderEvidenceApprovalRule(
      "required-artifacts",
      missingArtifactState,
      localized(
        `${artifactCoverage.submittedRequiredCount}/${artifactCoverage.requiredCount} required artifacts submitted; missing ${missingIds}.`,
        `已提交 ${artifactCoverage.submittedRequiredCount}/${artifactCoverage.requiredCount} 个必需证据；缺失 ${missingIds}。`,
        `已提交 ${artifactCoverage.submittedRequiredCount}/${artifactCoverage.requiredCount} 個必需證據；缺失 ${missingIds}。`,
      ),
      artifactCoverage.complete
        ? localized("Keep required artifact references attached.", "保留已附上的必需证据引用。", "保留已附上的必需證據引用。")
        : localized(
          `Attach missing required artifact references: ${missingIds}.`,
          `补齐缺失的必需证据引用：${missingIds}。`,
          `補齊缺失的必需證據引用：${missingIds}。`,
        ),
    ),
    walletProviderEvidenceApprovalRule(
      "reviewer-approval",
      reviewerApprovalState,
      localized(
        `Reviewer state is ${scenario.reviewState}; evidence status is ${scenario.evidenceStatus}.`,
        `审核状态为 ${scenario.reviewState}；证据状态为 ${scenario.evidenceStatus}。`,
        `審核狀態為 ${scenario.reviewState}；證據狀態為 ${scenario.evidenceStatus}。`,
      ),
      scenario.evidenceStatus === "approved"
        ? localized("Keep reviewer approval linked to this scenario.", "保留该场景的审核批准关联。", "保留該場景的審核批准關聯。")
        : scenario.nextAction,
    ),
    walletProviderEvidenceApprovalRule(
      "live-evidence-status",
      liveEvidenceRuleState,
      localized(
        `QA live evidence status is ${liveEvidenceStatus}; intake evidence status is ${scenario.evidenceStatus}.`,
        `QA 真实证据状态为 ${liveEvidenceStatus}；intake 证据状态为 ${scenario.evidenceStatus}。`,
        `QA 真實證據狀態為 ${liveEvidenceStatus}；intake 證據狀態為 ${scenario.evidenceStatus}。`,
      ),
      liveEvidenceRuleState === "passed"
        ? localized("Keep live evidence metadata review-linked.", "保留真实证据 metadata 的审核关联。", "保留真實證據 metadata 的審核關聯。")
        : scenario.nextAction,
    ),
    walletProviderEvidenceApprovalRule(
      "service-gate",
      serviceGateState,
      scenario.serviceGate,
      serviceGateState === "passed"
        ? localized(
          "Keep the wallet adapter service gate review-gated until all evidence rules pass.",
          "在所有证据规则通过前，保持钱包 adapter 服务门禁处于审核控制。",
          "在所有證據規則通過前，保持錢包 adapter 服務門禁處於審核控制。",
        )
        : localized(
          "Do not enable this wallet provider path while the service gate is blocked.",
          "服务门禁阻断时不要启用该钱包 provider 路径。",
          "服務門禁阻斷時不要啟用該錢包 provider 路徑。",
        ),
    ),
    walletProviderEvidenceApprovalRule(
      "non-live-boundary",
      "passed",
      scenario.boundary,
      localized(
        "Keep this approval audit as display metadata only.",
        "保持该 approval audit 仅作为展示 metadata。",
        "保持該 approval audit 僅作為展示 metadata。",
      ),
    ),
  ];
};

const createWalletProviderReviewerDecision = (
  scenario: WalletProviderEvidenceScenario,
  artifactCoverage: WalletProviderArtifactCoverage,
  approvalState: WalletProviderEvidenceApprovalScenario["approvalState"],
): WalletProviderReviewerDecision => {
  if (approvalState === "approved") {
    return {
      state: "approved",
      label: localized("Approved", "已批准", "已批准"),
      reason: localized(
        "Required artifacts, reviewer approval, live evidence status, service gate, and non-live boundary rules pass for this scenario.",
        "该场景的必需证据、审核批准、真实证据状态、服务门禁和非实时边界规则均已通过。",
        "該場景的必需證據、審核批准、真實證據狀態、服務門禁和非即時邊界規則均已通過。",
      ),
      nextAction: localized("Keep approval evidence attached for release review.", "为发布审核保留批准证据。", "為發布審核保留批准證據。"),
    };
  }

  if (scenario.evidenceStatus === "submitted") {
    const missingIds = walletProviderEvidenceApprovalIds(artifactCoverage.missingRequiredArtifactIds);

    return {
      state: "in_review",
      label: localized("Review required", "需要审核", "需要審核"),
      reason: localized(
        `Submitted evidence is not approved and is missing required artifacts: ${missingIds}.`,
        `已提交证据尚未批准，且缺失必需证据：${missingIds}。`,
        `已提交證據尚未批准，且缺失必需證據：${missingIds}。`,
      ),
      nextAction: scenario.nextAction,
    };
  }

  if (scenario.evidenceStatus === "rejected") {
    return {
      state: "rejected",
      label: localized("Rejected", "已拒绝", "已拒絕"),
      reason: localized(
        "Rejected provider evidence remains blocking until a complete replacement is submitted and approved.",
        "已拒绝的 provider 证据在提交并批准完整替代证据前持续阻断。",
        "已拒絕的 provider 證據在提交並批准完整替代證據前持續阻斷。",
      ),
      nextAction: scenario.nextAction,
    };
  }

  if (scenario.evidenceStatus === "expired") {
    return {
      state: "expired",
      label: localized("Expired", "已过期", "已過期"),
      reason: localized(
        "Expired provider evidence must be replaced before release review.",
        "已过期 provider 证据必须在发布审核前替换。",
        "已過期 provider 證據必須在發布審核前替換。",
      ),
      nextAction: scenario.nextAction,
    };
  }

  if (scenario.evidenceStatus === "not_applicable") {
    return {
      state: "not_applicable",
      label: localized("Not applicable", "不适用", "不適用"),
      reason: localized(
        "This wallet provider evidence scenario is not applicable.",
        "该钱包 provider 证据场景不适用。",
        "該錢包 provider 證據場景不適用。",
      ),
      nextAction: scenario.nextAction,
    };
  }

  return {
    state: "not_started",
    label: localized("Not started", "未开始", "未開始"),
    reason: localized(
      "No complete provider evidence has been attached for approval review.",
      "尚未附上可进入批准审核的完整 provider 证据。",
      "尚未附上可進入批准審核的完整 provider 證據。",
    ),
    nextAction: scenario.nextAction,
  };
};

const createWalletProviderEvidenceApprovalScenario = (
  scenario: WalletProviderEvidenceScenario,
  gate: WalletProviderQaReadinessGate,
): WalletProviderEvidenceApprovalScenario => {
  const qaScenario = gate.scenarios.find((item) => item.id === scenario.id);
  const artifactCoverage = createWalletProviderArtifactCoverage(scenario);
  const rules = createWalletProviderApprovalRules(scenario, qaScenario, artifactCoverage);
  const failedRuleIds = rules
    .filter((rule) => rule.state === "blocked" || rule.state === "needs_review")
    .map((rule) => rule.id);
  const approvalState: WalletProviderEvidenceApprovalScenario["approvalState"] =
    scenario.evidenceStatus === "not_applicable"
      ? "not_applicable"
      : rules.some((rule) => rule.state === "blocked")
        ? "blocked"
        : rules.some((rule) => rule.state === "needs_review")
          ? "review_required"
          : "approved";
  const reviewerDecision = createWalletProviderReviewerDecision(scenario, artifactCoverage, approvalState);

  return {
    approvalState,
    artifactCoverage,
    boundary: scenario.boundary,
    failedRuleIds,
    id: scenario.id,
    label: scenario.label,
    nextAction: reviewerDecision.nextAction,
    provider: scenario.provider,
    releaseImpact: walletProviderEvidenceApprovalReleaseImpact[approvalState],
    reviewerDecision,
    rules,
  };
};

const compareWalletProviderEvidenceApprovalScenarios = (
  left: WalletProviderEvidenceApprovalScenario,
  right: WalletProviderEvidenceApprovalScenario,
) => {
  const approvalDelta = walletProviderEvidenceApprovalStatePriority[left.approvalState] -
    walletProviderEvidenceApprovalStatePriority[right.approvalState];

  if (approvalDelta !== 0) {
    return approvalDelta;
  }

  const leftFailedRule = left.rules.find((rule) => rule.id === left.failedRuleIds[0]);
  const rightFailedRule = right.rules.find((rule) => rule.id === right.failedRuleIds[0]);
  const failedRuleDelta = walletProviderEvidenceApprovalRuleStatePriority[leftFailedRule?.state ?? "passed"] -
    walletProviderEvidenceApprovalRuleStatePriority[rightFailedRule?.state ?? "passed"];

  if (failedRuleDelta !== 0) {
    return failedRuleDelta;
  }

  return walletProviderEvidenceScenarioOrder.indexOf(left.id) - walletProviderEvidenceScenarioOrder.indexOf(right.id);
};

const summarizeWalletProviderEvidenceApprovalAudit = (
  scenarios: WalletProviderEvidenceApprovalScenario[],
): WalletProviderEvidenceApprovalAudit["summary"] => {
  const topScenario = [...scenarios].sort(compareWalletProviderEvidenceApprovalScenarios)[0] ?? scenarios[0];
  const topFailedRuleId = topScenario?.failedRuleIds[0] ?? null;
  const topFailedRule = topFailedRuleId
    ? topScenario.rules.find((rule) => rule.id === topFailedRuleId) ?? null
    : null;

  return {
    totalScenarios: scenarios.length,
    approvedScenarios: scenarios.filter((scenario) => scenario.approvalState === "approved").length,
    reviewRequiredScenarios: scenarios.filter((scenario) => scenario.approvalState === "review_required").length,
    blockedScenarios: scenarios.filter((scenario) => scenario.approvalState === "blocked").length,
    notApplicableScenarios: scenarios.filter((scenario) => scenario.approvalState === "not_applicable").length,
    completeArtifactScenarios: scenarios.filter((scenario) => scenario.artifactCoverage.complete).length,
    incompleteArtifactScenarios: scenarios.filter((scenario) => !scenario.artifactCoverage.complete).length,
    releaseBlockers: scenarios.filter((scenario) => scenario.releaseImpact === "blocked").length,
    topScenarioId: topScenario.id,
    topFailedRuleId,
    topFailedRuleState: topFailedRule?.state ?? null,
    topNextAction: topScenario.nextAction,
  };
};

export const createWalletProviderEvidenceApprovalAudit = (
  intake: WalletProviderEvidenceIntake,
  gate: WalletProviderQaReadinessGate,
): WalletProviderEvidenceApprovalAudit => {
  const scenarios = walletProviderEvidenceScenarioOrder
    .map((scenarioId) => intake.scenarios.find((scenario) => scenario.id === scenarioId))
    .filter((scenario): scenario is WalletProviderEvidenceScenario => Boolean(scenario))
    .map((scenario) => createWalletProviderEvidenceApprovalScenario(scenario, gate));
  const summary = summarizeWalletProviderEvidenceApprovalAudit(scenarios);

  return {
    boundary: walletProviderEvidenceBoundary,
    nextAction: summary.topNextAction,
    scenarios,
    summary,
  };
};

const requiredWalletProviderReleaseScenarioIds = new Set<WalletProviderQaScenarioId>(
  walletProviderEvidenceScenarioOrder,
);

const walletProviderEvidenceReleaseStatePriority: Record<WalletProviderEvidenceReleaseState, number> = {
  blocked: 0,
  review_required: 1,
  ready: 2,
  not_applicable: 3,
};

const createWalletProviderEvidenceReleaseScenario = (
  scenario: WalletProviderEvidenceApprovalScenario,
): WalletProviderEvidenceReleaseScenario => {
  const requiredForRelease = requiredWalletProviderReleaseScenarioIds.has(scenario.id);
  const blockingRuleIds = scenario.rules
    .filter((rule) => rule.state === "blocked")
    .map((rule) => rule.id);
  const reviewRequiredRuleIds = scenario.rules
    .filter((rule) => rule.state === "needs_review")
    .map((rule) => rule.id);
  const completeRequiredApproval =
    scenario.approvalState === "approved" &&
    scenario.artifactCoverage.complete &&
    scenario.failedRuleIds.length === 0;
  const releaseState: WalletProviderEvidenceReleaseState =
    !requiredForRelease && scenario.approvalState === "not_applicable"
      ? "not_applicable"
      : completeRequiredApproval
        ? "ready"
        : blockingRuleIds.length > 0 || (requiredForRelease && scenario.approvalState === "not_applicable")
          ? "blocked"
          : "review_required";

  return {
    approvalState: scenario.approvalState,
    artifactCoverage: scenario.artifactCoverage,
    blockingRuleIds,
    boundary: scenario.boundary,
    failedRuleIds: scenario.failedRuleIds,
    id: scenario.id,
    label: scenario.label,
    nextAction: scenario.nextAction,
    provider: scenario.provider,
    releaseState,
    requiredForRelease,
    reviewRequiredRuleIds,
  };
};

const compareWalletProviderEvidenceReleaseScenarios = (
  left: WalletProviderEvidenceReleaseScenario,
  right: WalletProviderEvidenceReleaseScenario,
) => {
  const stateDelta = walletProviderEvidenceReleaseStatePriority[left.releaseState] -
    walletProviderEvidenceReleaseStatePriority[right.releaseState];

  if (stateDelta !== 0) {
    return stateDelta;
  }

  const requiredDelta = Number(right.requiredForRelease) - Number(left.requiredForRelease);

  if (requiredDelta !== 0) {
    return requiredDelta;
  }

  return walletProviderEvidenceScenarioOrder.indexOf(left.id) - walletProviderEvidenceScenarioOrder.indexOf(right.id);
};

const summarizeWalletProviderEvidenceReleaseReadiness = (
  scenarios: WalletProviderEvidenceReleaseScenario[],
): WalletProviderEvidenceReleaseReadiness["summary"] => {
  const requiredScenarios = scenarios.filter((scenario) => scenario.requiredForRelease);
  const topScenario = [...requiredScenarios].sort(compareWalletProviderEvidenceReleaseScenarios)[0] ??
    [...scenarios].sort(compareWalletProviderEvidenceReleaseScenarios)[0] ??
    scenarios[0];
  const approvedRequiredScenarios = requiredScenarios.filter((scenario) => scenario.releaseState === "ready").length;
  const reviewRequiredScenarios = requiredScenarios.filter((scenario) => scenario.releaseState === "review_required").length;
  const blockedScenarios = requiredScenarios.filter((scenario) => scenario.releaseState === "blocked").length;
  const topFailedRuleId = topScenario?.failedRuleIds[0] ?? null;
  const ready =
    requiredScenarios.length > 0 &&
    approvedRequiredScenarios === requiredScenarios.length &&
    reviewRequiredScenarios === 0 &&
    blockedScenarios === 0;

  return {
    approvedRequiredScenarios,
    blockedScenarios,
    notApplicableScenarios: scenarios.filter((scenario) => scenario.releaseState === "not_applicable").length,
    ready,
    releaseBlockers: blockedScenarios,
    requiredScenarios: requiredScenarios.length,
    reviewRequiredScenarios,
    topFailedRuleId,
    topNextAction: ready
      ? localized(
        "Keep all approved wallet provider evidence attached for release review; live execution still requires a separate enablement decision.",
        "为发布审核保留所有已批准的钱包 provider 证据；真实执行仍需要单独启用决策。",
        "為發布審核保留所有已批准的錢包 provider 證據；真實執行仍需要單獨啟用決策。",
      )
      : topScenario.nextAction,
    topScenarioId: topScenario.id,
    totalScenarios: scenarios.length,
  };
};

export const createWalletProviderEvidenceReleaseReadiness = (
  approvalAudit: WalletProviderEvidenceApprovalAudit,
): WalletProviderEvidenceReleaseReadiness => {
  const scenarios = walletProviderEvidenceScenarioOrder
    .map((scenarioId) => approvalAudit.scenarios.find((scenario) => scenario.id === scenarioId))
    .filter((scenario): scenario is WalletProviderEvidenceApprovalScenario => Boolean(scenario))
    .map(createWalletProviderEvidenceReleaseScenario);
  const summary = summarizeWalletProviderEvidenceReleaseReadiness(scenarios);

  return {
    boundary: walletProviderEvidenceBoundary,
    nextAction: summary.topNextAction,
    scenarios,
    summary,
  };
};

const walletProviderEvidenceCloseoutSignoffState = (
  scenario: WalletProviderEvidenceReleaseScenario,
): WalletProviderEvidenceCloseoutSignoffState => {
  if (!scenario.requiredForRelease && scenario.releaseState === "not_applicable") {
    return "not_applicable";
  }

  if (scenario.releaseState === "ready") {
    return "ready";
  }

  return scenario.releaseState === "review_required" ? "review_required" : "blocked";
};

const walletProviderEvidenceCloseoutScenario = (
  scenario: WalletProviderEvidenceReleaseScenario,
): WalletProviderEvidenceCloseoutScenario => {
  const attachedEvidenceReferences = scenario.artifactCoverage.submittedArtifactReferences;

  return {
    approvalState: scenario.approvalState,
    attachedEvidenceReferences,
    blockingRuleIds: scenario.blockingRuleIds,
    boundary: scenario.boundary,
    failedRuleIds: scenario.failedRuleIds,
    id: scenario.id,
    label: scenario.label,
    missingRequiredArtifactIds: scenario.artifactCoverage.missingRequiredArtifactIds,
    nextAction: scenario.nextAction,
    provider: scenario.provider,
    releaseState: scenario.releaseState,
    requiredArtifactCount: scenario.artifactCoverage.requiredCount,
    requiredForRelease: scenario.requiredForRelease,
    reviewRequiredRuleIds: scenario.reviewRequiredRuleIds,
    signoffState: walletProviderEvidenceCloseoutSignoffState(scenario),
    submittedRequiredArtifactCount: scenario.artifactCoverage.submittedRequiredCount,
  };
};

const walletProviderEvidenceCloseoutStatePriority: Record<WalletProviderEvidenceCloseoutSignoffState, number> = {
  blocked: 0,
  review_required: 1,
  ready: 2,
  not_applicable: 3,
};

const compareWalletProviderEvidenceCloseoutScenarios = (
  left: WalletProviderEvidenceCloseoutScenario,
  right: WalletProviderEvidenceCloseoutScenario,
) => {
  const stateDelta = walletProviderEvidenceCloseoutStatePriority[left.signoffState] -
    walletProviderEvidenceCloseoutStatePriority[right.signoffState];

  if (stateDelta !== 0) {
    return stateDelta;
  }

  const requiredDelta = Number(right.requiredForRelease) - Number(left.requiredForRelease);

  if (requiredDelta !== 0) {
    return requiredDelta;
  }

  return walletProviderEvidenceScenarioOrder.indexOf(left.id) - walletProviderEvidenceScenarioOrder.indexOf(right.id);
};

const summarizeWalletProviderEvidenceCloseoutPackage = (
  scenarios: WalletProviderEvidenceCloseoutScenario[],
): WalletProviderEvidenceCloseoutPackage["summary"] => {
  const requiredScenarios = scenarios.filter((scenario) => scenario.requiredForRelease);
  const topScenario = [...requiredScenarios].sort(compareWalletProviderEvidenceCloseoutScenarios)[0] ??
    [...scenarios].sort(compareWalletProviderEvidenceCloseoutScenarios)[0] ??
    scenarios[0];
  const approvedRequiredScenarios = requiredScenarios.filter((scenario) => scenario.signoffState === "ready").length;
  const reviewRequiredScenarios = requiredScenarios.filter((scenario) => scenario.signoffState === "review_required").length;
  const blockedScenarios = requiredScenarios.filter((scenario) => scenario.signoffState === "blocked").length;
  const closeoutBlockers = blockedScenarios;
  const ready =
    requiredScenarios.length > 0 &&
    approvedRequiredScenarios === requiredScenarios.length &&
    reviewRequiredScenarios === 0 &&
    closeoutBlockers === 0;

  return {
    approvedRequiredScenarios,
    attachedEvidenceReferences: scenarios.reduce(
      (total, scenario) => total + scenario.attachedEvidenceReferences.length,
      0,
    ),
    blockedScenarios,
    closeoutBlockers,
    missingRequiredArtifacts: scenarios.reduce(
      (total, scenario) => total + scenario.missingRequiredArtifactIds.length,
      0,
    ),
    ready,
    readyForReviewScenarios: requiredScenarios.filter((scenario) => scenario.signoffState === "ready").length,
    requiredScenarios: requiredScenarios.length,
    reviewRequiredScenarios,
    topFailedRuleId: topScenario?.failedRuleIds[0] ?? null,
    topNextAction: ready
      ? localized(
        "Closeout package is ready for release review; keep the no-live boundary until a separate production enablement decision.",
        "Closeout package 已可进入发布审核；在单独生产启用决策前继续保留非实时边界。",
        "Closeout package 已可進入發布審核；在單獨生產啟用決策前繼續保留非即時邊界。",
      )
      : topScenario.nextAction,
    topScenarioId: topScenario.id,
    totalScenarios: scenarios.length,
  };
};

export const createWalletProviderEvidenceCloseoutPackage = (
  releaseReadiness: WalletProviderEvidenceReleaseReadiness,
): WalletProviderEvidenceCloseoutPackage => {
  const scenarios = walletProviderEvidenceScenarioOrder
    .map((scenarioId) => releaseReadiness.scenarios.find((scenario) => scenario.id === scenarioId))
    .filter((scenario): scenario is WalletProviderEvidenceReleaseScenario => Boolean(scenario))
    .map(walletProviderEvidenceCloseoutScenario);
  const summary = summarizeWalletProviderEvidenceCloseoutPackage(scenarios);

  return {
    boundary: releaseReadiness.boundary,
    nextAction: summary.topNextAction,
    scenarios,
    summary,
  };
};

const walletProviderEvidenceRequestStatusFor = (
  scenario: WalletProviderEvidenceCloseoutScenario,
): WalletProviderEvidenceRequestStatus => {
  if (!scenario.requiredForRelease && scenario.signoffState === "not_applicable") {
    return "not_applicable";
  }

  return scenario.signoffState;
};

const walletProviderEvidenceRequestStatusPriority: Record<WalletProviderEvidenceRequestStatus, number> = {
  blocked: 0,
  review_required: 1,
  ready: 2,
  not_applicable: 3,
};

const walletProviderEvidenceTargetPath = (
  scenarioId: WalletProviderQaScenarioId,
) => `wallet-provider-evidence/${scenarioId}/`;

const walletProviderEvidenceAcceptanceCriteria = (
  scenario: WalletProviderEvidenceCloseoutScenario,
): LocalizedText => {
  const missingArtifacts = walletProviderEvidenceApprovalIds(scenario.missingRequiredArtifactIds);
  const failedRules = walletProviderEvidenceApprovalIds(scenario.failedRuleIds);

  if (scenario.signoffState === "ready") {
    return localized(
      `All required artifacts are attached and approved for ${scenario.id}; keep reviewer approval linked before release review.`,
      `${scenario.id} 的所有必需 artifact 已附上并批准；发布审核前保留审核批准关联。`,
      `${scenario.id} 的所有必需 artifact 已附上並批准；發布審核前保留審核批准關聯。`,
    );
  }

  if (scenario.signoffState === "review_required") {
    return localized(
      `Reviewer must approve submitted evidence and resolve missing artifacts: ${missingArtifacts}.`,
      `审核人必须批准已提交证据，并补齐缺失 artifacts：${missingArtifacts}。`,
      `審核人必須批准已提交證據，並補齊缺失 artifacts：${missingArtifacts}。`,
    );
  }

  if (scenario.signoffState === "not_applicable") {
    return localized(
      "Confirm this wallet provider scenario is not required for release.",
      "确认该钱包 provider 场景不属于发布必需项。",
      "確認該錢包 provider 場景不屬於發布必需項。",
    );
  }

  return localized(
    `Attach all missing required artifacts (${missingArtifacts}) and clear blocking rules: ${failedRules}.`,
    `附上所有缺失的必需 artifacts（${missingArtifacts}），并清除阻断规则：${failedRules}。`,
    `附上所有缺失的必需 artifacts（${missingArtifacts}），並清除阻斷規則：${failedRules}。`,
  );
};

const walletProviderEvidenceCaptureInstructions = (
  scenario: WalletProviderEvidenceCloseoutScenario,
): LocalizedText => localized(
  `Capture live QA evidence for ${scenario.id}: screenshot, QA run ID, reviewer note, and runbook where required; attach references under ${walletProviderEvidenceTargetPath(scenario.id)} without using the app to upload or execute wallet operations.`,
  `采集 ${scenario.id} 的真实 QA 证据：截图、QA run ID、审核备注，以及需要时的 runbook；将引用记录到 ${walletProviderEvidenceTargetPath(scenario.id)}，不要通过应用上传或执行钱包操作。`,
  `採集 ${scenario.id} 的真實 QA 證據：截圖、QA run ID、審核備註，以及需要時的 runbook；將引用記錄到 ${walletProviderEvidenceTargetPath(scenario.id)}，不要透過應用上傳或執行錢包操作。`,
);

const walletProviderEvidenceRequestScenario = (
  scenario: WalletProviderEvidenceCloseoutScenario,
): Omit<WalletProviderEvidenceRequestScenario, "priority"> => ({
  acceptanceCriteria: walletProviderEvidenceAcceptanceCriteria(scenario),
  attachedEvidenceReferences: scenario.attachedEvidenceReferences,
  blockingRuleIds: scenario.blockingRuleIds,
  boundary: scenario.boundary,
  failedRuleIds: scenario.failedRuleIds,
  id: scenario.id,
  label: scenario.label,
  missingRequiredArtifactIds: scenario.missingRequiredArtifactIds,
  nextAction: scenario.nextAction,
  ownerRole: "internal_operator",
  provider: scenario.provider,
  qaCaptureInstructions: walletProviderEvidenceCaptureInstructions(scenario),
  requestStatus: walletProviderEvidenceRequestStatusFor(scenario),
  requiredArtifactIds: expectedWalletProviderArtifacts(scenario.id)
    .filter((artifact) => artifact.required)
    .map((artifact) => artifact.id),
  requiredForRelease: scenario.requiredForRelease,
  reviewerRole: "internal_operator",
  reviewRequiredRuleIds: scenario.reviewRequiredRuleIds,
  targetEvidencePath: walletProviderEvidenceTargetPath(scenario.id),
});

const compareWalletProviderEvidenceRequestScenarios = (
  left: Omit<WalletProviderEvidenceRequestScenario, "priority">,
  right: Omit<WalletProviderEvidenceRequestScenario, "priority">,
) => {
  const stateDelta = walletProviderEvidenceRequestStatusPriority[left.requestStatus] -
    walletProviderEvidenceRequestStatusPriority[right.requestStatus];

  if (stateDelta !== 0) {
    return stateDelta;
  }

  const requiredDelta = Number(right.requiredForRelease) - Number(left.requiredForRelease);

  if (requiredDelta !== 0) {
    return requiredDelta;
  }

  return walletProviderEvidenceScenarioOrder.indexOf(left.id) - walletProviderEvidenceScenarioOrder.indexOf(right.id);
};

const summarizeWalletProviderEvidenceRequestPacket = (
  scenarios: WalletProviderEvidenceRequestScenario[],
): WalletProviderEvidenceRequestPacket["summary"] => {
  const requiredScenarios = scenarios.filter((scenario) => scenario.requiredForRelease);
  const topScenario = [...requiredScenarios].sort(compareWalletProviderEvidenceRequestScenarios)[0] ??
    [...scenarios].sort(compareWalletProviderEvidenceRequestScenarios)[0] ??
    scenarios[0];
  const readyRequests = requiredScenarios.filter((scenario) => scenario.requestStatus === "ready").length;
  const reviewRequiredRequests = requiredScenarios.filter((scenario) => scenario.requestStatus === "review_required").length;
  const blockedRequests = requiredScenarios.filter((scenario) => scenario.requestStatus === "blocked").length;
  const launchBlockingRequests = blockedRequests;
  const ready =
    requiredScenarios.length > 0 &&
    readyRequests === requiredScenarios.length &&
    reviewRequiredRequests === 0 &&
    launchBlockingRequests === 0;

  return {
    attachedEvidenceReferences: scenarios.reduce(
      (total, scenario) => total + scenario.attachedEvidenceReferences.length,
      0,
    ),
    blockedRequests,
    launchBlockingRequests,
    missingRequiredArtifacts: scenarios.reduce(
      (total, scenario) => total + scenario.missingRequiredArtifactIds.length,
      0,
    ),
    notApplicableRequests: scenarios.filter((scenario) => scenario.requestStatus === "not_applicable").length,
    ready,
    readyRequests,
    reviewRequiredRequests,
    topFailedRuleId: topScenario?.failedRuleIds[0] ?? null,
    topNextAction: ready
      ? localized(
        "Evidence request packet is ready for release review; keep the no-live boundary until a separate production enablement decision.",
        "Evidence request packet 已可进入发布审核；在单独生产启用决策前继续保留非实时边界。",
        "Evidence request packet 已可進入發布審核；在單獨生產啟用決策前繼續保留非即時邊界。",
      )
      : topScenario.nextAction,
    topScenarioId: topScenario.id,
    totalRequests: scenarios.length,
  };
};

export const createWalletProviderEvidenceRequestPacket = (
  closeoutPackage: WalletProviderEvidenceCloseoutPackage,
): WalletProviderEvidenceRequestPacket => {
  const scenarios = closeoutPackage.scenarios
    .map(walletProviderEvidenceRequestScenario)
    .sort(compareWalletProviderEvidenceRequestScenarios)
    .map((scenario, index) => ({
      ...scenario,
      priority: index + 1,
    }));
  const summary = summarizeWalletProviderEvidenceRequestPacket(scenarios);

  return {
    boundary: closeoutPackage.boundary,
    nextAction: summary.topNextAction,
    scenarios,
    summary,
  };
};

const walletProviderEvidenceActivationBoundary = localized(
  "No live wallet SDK, provider call, signature, contract write, storage write, export file, reward custody, or reward distribution is executed by this activation projection.",
  "该 activation projection 不会执行实时钱包 SDK、provider 调用、签名、合约写入、存储写入、导出文件、奖励托管或发奖。",
  "該 activation projection 不會執行即時錢包 SDK、provider 呼叫、簽名、合約寫入、儲存寫入、匯出檔案、獎勵託管或發獎。",
);

const walletProviderEvidenceActivationReadyAction = localized(
  "Scenario is ready for local activation review; keep the no-live boundary until production enablement is approved.",
  "该场景已可进入本地 activation 审核；在生产启用批准前继续保持非实时边界。",
  "該場景已可進入本地 activation 審核；在生產啟用批准前繼續保持非即時邊界。",
);

const walletProviderEvidenceActivationArtifactTypeFromId = (
  value: string,
): WalletProviderEvidenceActivationArtifactRow["artifactType"] => {
  if (value.includes("screenshot")) {
    return "screenshot";
  }

  if (value.includes("qa-run") || value.includes("qa_run") || value.includes("run-")) {
    return "qa_run";
  }

  if (value.includes("runbook")) {
    return "runbook";
  }

  if (value.includes("config")) {
    return "config_snapshot";
  }

  return "review_note";
};

const walletProviderEvidenceActivationSubmittedArtifacts = (
  releaseScenario: WalletProviderEvidenceReleaseScenario | undefined,
): WalletProviderEvidenceActivationArtifactRow[] => {
  if (!releaseScenario) {
    return [];
  }

  const status: WalletProviderEvidenceActivationArtifactRow["status"] =
    releaseScenario.releaseState === "ready" ? "approved" : "submitted";

  return releaseScenario.artifactCoverage.submittedArtifactReferences.map((reference, index) => {
    const artifactId = releaseScenario.artifactCoverage.submittedArtifactIds[index] ?? reference;

    return {
      artifactType: walletProviderEvidenceActivationArtifactTypeFromId(artifactId),
      reference,
      status,
    };
  });
};

const walletProviderEvidenceActivationLiveEvidenceStatus = (
  releaseScenario: WalletProviderEvidenceReleaseScenario | undefined,
) => {
  if (!releaseScenario) {
    return "missing" as const;
  }

  if (releaseScenario.releaseState === "ready") {
    return "ready" as const;
  }

  if (releaseScenario.blockingRuleIds.includes("live-evidence-status")) {
    return "blocked" as const;
  }

  return "missing" as const;
};

const walletProviderEvidenceActivationFeatureGateState = (
  releaseScenario: WalletProviderEvidenceReleaseScenario | undefined,
): WalletProviderEvidenceActivationFeatureGateState => {
  if (!releaseScenario) {
    return "disabled";
  }

  if (releaseScenario.releaseState === "ready") {
    return "approved";
  }

  if (releaseScenario.blockingRuleIds.includes("service-gate")) {
    return "blocked";
  }

  if (releaseScenario.reviewRequiredRuleIds.includes("service-gate")) {
    return "review_required";
  }

  return "disabled";
};

const walletProviderEvidenceActivationReviewerState = (
  releaseScenario: WalletProviderEvidenceReleaseScenario | undefined,
): WalletProviderEvidenceActivationReviewerState => {
  if (!releaseScenario) {
    return "pending";
  }

  if (releaseScenario.approvalState === "approved") {
    return "approved";
  }

  if (
    releaseScenario.releaseState === "blocked" &&
    releaseScenario.blockingRuleIds.includes("service-gate")
  ) {
    return "rejected";
  }

  return "pending";
};

const walletProviderEvidenceActivationBlockerIds = ({
  featureGateState,
  liveEvidenceStatus,
  missingArtifactTypes,
  releaseState,
  reviewerState,
}: Pick<
  WalletProviderEvidenceActivationScenario,
  "featureGateState" | "liveEvidenceStatus" | "missingArtifactTypes" | "releaseState" | "reviewerState"
>): WalletProviderEvidenceActivationBlockerId[] => {
  const blockerIds: WalletProviderEvidenceActivationBlockerId[] = [];

  if (missingArtifactTypes.length > 0) {
    blockerIds.push("missing-artifacts");
  }

  if (liveEvidenceStatus !== "ready") {
    blockerIds.push("live-evidence-not-ready");
  }

  if (featureGateState !== "approved") {
    blockerIds.push("feature-gate-not-approved");
  }

  if (reviewerState !== "approved") {
    blockerIds.push("reviewer-approval-required");
  }

  if (releaseState !== "ready") {
    blockerIds.push("release-readiness-not-ready");
  }

  return blockerIds;
};

const walletProviderEvidenceActivationStateFor = (
  blockerIds: WalletProviderEvidenceActivationBlockerId[],
  releaseState: WalletProviderEvidenceReleaseState,
): WalletProviderEvidenceActivationScenario["activationState"] => {
  if (blockerIds.length === 0) {
    return "ready";
  }

  return releaseState === "review_required" ? "review_required" : "blocked";
};

const walletProviderEvidenceActivationDependency = (
  scenario: WalletProviderEvidenceRequestScenario,
): LocalizedText => localized(
  `Feature gate and reviewer approval for ${scenario.id} must remain linked to ${scenario.targetEvidencePath}.`,
  `${scenario.id} 的 feature gate 与审核批准必须继续关联到 ${scenario.targetEvidencePath}。`,
  `${scenario.id} 的 feature gate 與審核批准必須繼續關聯到 ${scenario.targetEvidencePath}。`,
);

const createWalletProviderEvidenceActivationScenario = (
  scenario: WalletProviderEvidenceRequestScenario,
  releaseReadiness: WalletProviderEvidenceReleaseReadiness,
  overrides: WalletProviderEvidenceActivationOverrides = {},
): WalletProviderEvidenceActivationScenario => {
  const releaseScenario = releaseReadiness.scenarios.find((candidate) => candidate.id === scenario.id);
  const override = overrides[scenario.id];
  const requiredArtifactTypes = expectedWalletProviderArtifacts(scenario.id)
    .filter((artifact) => artifact.required)
    .map((artifact) => artifact.artifactType);
  const submittedArtifacts =
    override?.submittedArtifacts ?? walletProviderEvidenceActivationSubmittedArtifacts(releaseScenario);
  const missingArtifactTypes =
    override?.missingArtifactTypes ??
    scenario.missingRequiredArtifactIds.map(walletProviderEvidenceActivationArtifactTypeFromId);
  const liveEvidenceStatus =
    override?.liveEvidenceStatus ?? walletProviderEvidenceActivationLiveEvidenceStatus(releaseScenario);
  const featureGateState =
    override?.featureGateState ?? walletProviderEvidenceActivationFeatureGateState(releaseScenario);
  const reviewerState =
    override?.reviewerState ?? walletProviderEvidenceActivationReviewerState(releaseScenario);
  const releaseState = override?.releaseState ?? releaseScenario?.releaseState ?? "blocked";
  const blockerIds = walletProviderEvidenceActivationBlockerIds({
    featureGateState,
    liveEvidenceStatus,
    missingArtifactTypes,
    releaseState,
    reviewerState,
  });
  const activationState = walletProviderEvidenceActivationStateFor(blockerIds, releaseState);

  return {
    activationState,
    blockerIds,
    boundary: walletProviderEvidenceActivationBoundary,
    dependency: walletProviderEvidenceActivationDependency(scenario),
    evidenceNeeded: scenario.qaCaptureInstructions,
    featureGateState,
    id: scenario.id,
    liveEvidenceStatus,
    missingArtifactTypes,
    nextAction: activationState === "ready" ? walletProviderEvidenceActivationReadyAction : scenario.nextAction,
    ownerRole: scenario.ownerRole,
    releaseState,
    requiredArtifactTypes,
    reviewerState,
    submittedArtifacts,
    title: scenario.label,
  };
};

const walletProviderEvidenceActivationStatePriority: Record<
  WalletProviderEvidenceActivationScenario["activationState"],
  number
> = {
  blocked: 0,
  review_required: 1,
  ready: 2,
};

const compareWalletProviderEvidenceActivationScenarios = (
  left: WalletProviderEvidenceActivationScenario,
  right: WalletProviderEvidenceActivationScenario,
) => {
  const stateDelta = walletProviderEvidenceActivationStatePriority[left.activationState] -
    walletProviderEvidenceActivationStatePriority[right.activationState];

  if (stateDelta !== 0) {
    return stateDelta;
  }

  return walletProviderEvidenceScenarioOrder.indexOf(left.id) - walletProviderEvidenceScenarioOrder.indexOf(right.id);
};

const summarizeWalletProviderEvidenceActivation = (
  scenarios: WalletProviderEvidenceActivationScenario[],
): WalletProviderEvidenceActivation["summary"] => {
  const topScenario = [...scenarios].sort(compareWalletProviderEvidenceActivationScenarios)[0] ?? scenarios[0];
  const readyScenarios = scenarios.filter((scenario) => scenario.activationState === "ready").length;
  const blockedScenarios = scenarios.filter((scenario) => scenario.activationState === "blocked").length;
  const reviewRequiredScenarios = scenarios.filter((scenario) => scenario.activationState === "review_required").length;
  const ready = scenarios.length > 0 && readyScenarios === scenarios.length;

  return {
    approvedFeatureGates: scenarios.filter((scenario) => scenario.featureGateState === "approved").length,
    blockedScenarios,
    missingArtifactTypeCount: scenarios.reduce(
      (total, scenario) => total + scenario.missingArtifactTypes.length,
      0,
    ),
    ready,
    readyScenarios,
    reviewRequiredScenarios,
    reviewerApprovedScenarios: scenarios.filter((scenario) => scenario.reviewerState === "approved").length,
    topBlockerId: topScenario?.blockerIds[0] ?? null,
    topScenarioId: topScenario.id,
    totalScenarios: scenarios.length,
  };
};

export const createWalletProviderEvidenceActivation = (
  requestPacket: WalletProviderEvidenceRequestPacket,
  releaseReadiness: WalletProviderEvidenceReleaseReadiness,
  overrides: WalletProviderEvidenceActivationOverrides = {},
): WalletProviderEvidenceActivation => {
  const scenarios = walletProviderEvidenceScenarioOrder
    .map((scenarioId) => requestPacket.scenarios.find((scenario) => scenario.id === scenarioId))
    .filter((scenario): scenario is WalletProviderEvidenceRequestScenario => Boolean(scenario))
    .map((scenario) => createWalletProviderEvidenceActivationScenario(scenario, releaseReadiness, overrides));
  const summary = summarizeWalletProviderEvidenceActivation(scenarios);

  return {
    boundary: walletProviderEvidenceActivationBoundary,
    nextAction: summary.ready ? walletProviderEvidenceActivationReadyAction : scenarios
      .find((scenario) => scenario.id === summary.topScenarioId)?.nextAction ?? requestPacket.nextAction,
    scenarios,
    summary,
  };
};

